#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard);
use HTML::Entities;

print header('text/html; charset=UTF-8');

my $comment = param('comment') || '';

$comment = encode_entities($comment, '<>&"\'');

$comment =~ s/&lt;b&gt;(.*?)&lt;\/b&gt;/<b>$1<\/b>/gs;
$comment =~ s/&lt;i&gt;(.*?)&lt;\/i&gt;/<i>$1<\/i>/gs;
$comment =~ s/&lt;u&gt;(.*?)&lt;\/u&gt;/<u>$1<\/u>/gs;
$comment =~ s/&lt;br\s*\/?&gt;/<br>/gi;
$comment =~ s/&lt;p&gt;(.*?)&lt;\/p&gt;/<p>$1<\/p>/gs;

print qq{<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<title>User Comments</title>
</head>
<body>
<div>$comment</div>
</body>
</html>
